{
  "name": "x-snc-customer-site-operations",
  "version": "1.0.0",
  "description": "Unified operations workspace for Schneider Electric MSSP. Provides cross-product visibility into Customer Cases, Security Incidents, OT Vulnerabilities, OT Changes, and OT Incidents — all filtered by Customer Account and OT Site.",
  "license": "UNLICENSED",
  "imports": {
    "#now:*": "./@types/servicenow/fluent/*/index.js"
  },
  "scripts": {
    "build": "now-sdk build",
    "deploy": "now-sdk install",
    "transform": "now-sdk transform",
    "types": "now-sdk dependencies"
  },
  "dependencies": {
    "react": "18.2.0",
    "react-dom": "18.2.0"
  },
  "devDependencies": {
    "@servicenow/sdk": "4.6.0",
    "@servicenow/glide": "27.0.5",
    "@types/react": "18.3.12"
  }
}
